mapper.select:
SELECT su.user_id, su.user_name, su.nick_name, su.email, su.phonenumber, su.status, su.create_time, sud.id as user_dept_id, sud.is_default as is_user_default_dept FROM sys_user su JOIN sys_user_dept sud on su.user_id = sud.user_id and sud.dept_id = #{deptId}
AND su.user_name like concat('%', #{param.userName}, '%')
AND su.phonenumber like concat('%', #{param.phonenumber}, '%')

select sud.id
from sys_user_dept sud
         join sys_dept sd on sud.dept_id = sd.dept_id and sd.org_id = #{orgId}
where sud.user_id = #{userId}
  and sud.is_default = 1

mapper.update:
update sys_user_dept
set is_default = null
where id = #{id}

